mapper.select:
select c.id, o.number as orderNumber, u.name as userName, u.avatar as userAvatar, c.score, c.content, c.create_time as createTime, c.reply_content as replyContent, c.reply_time as replyTime from comment c left join orders o on c.order_id = o.id left join user u on c.user_id = u.id
and c.score = #{score}
order by c.create_time desc

mapper.update:
update comment
set reply_content = #{replyContent}, reply_time = #{replyTime}
where id = #{id}
